// collector/benthos/input/myplugin.go
package input

import (
	"context"

	"github.com/redpanda-data/benthos/v4/public/service"
	"github.com/openmeterio/openmeter/collector/benthos/services/leaderelection"
)

func init() {
	err := service.RegisterBatchInput("my_plugin", MyPluginInputConfig(),
		func(conf *service.ParsedConfig, res *service.Resources) (service.BatchInput, error) {
			return newMyPluginInput(conf, res)
		})
	if err != nil {
		panic(err)
	}
}

type myPluginInput struct{ res *service.Resources }

func newMyPluginInput(conf *service.ParsedConfig, res *service.Resources) (*myPluginInput, error) {
	return &myPluginInput{res: res}, nil
}

func (p *myPluginInput) Connect(ctx context.Context) error {
	if !leaderelection.IsLeader(p.res) {
		return service.ErrNotConnected
	}
	return nil
}

func (p *myPluginInput) ReadBatch(ctx context.Context) (service.MessageBatch, service.AckFunc, error) {
	// ... fetch and return messages
	return nil, nil, service.ErrNotConnected
}

func (p *myPluginInput) Close(ctx context.Context) error { return nil }
